// Receives ALL accumulated done-branch items (one per processed stock)
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { summary_message: 'Report is done — no stocks analyzed.' } }];
}

const lines = items.map(item => {
  const j = item.json;
  const stock   = j.stock         || '?';
  const verdict = j.alert_verdict || 'HOLD';
  const conf    = j.confidence    ? ` (${j.confidence}%)` : '';
   const price   = j.current_price ? ` $${Number(j.current_price).toFixed(2)}` : '';
  const target  = j.pt_base       ? ` → $${Number(j.pt_base).toFixed(2)}`     : '';
  const ma      = j.ma_signal && j.ma_signal !== 'MA_DATA_UNAVAILABLE'
                    ? ` [${j.ma_signal}]` : '';
  const icon = verdict === 'BUY'  ? '🟢'
             : verdict === 'SELL' ? '🔴'
             :                      '🟡';
   return `${icon} ${stock}: ${verdict}${conf}${ma}${price}${target}`;
});

const today = new Date().toISOString().split('T')[0];
const summary_message =
  `📊 *Institutional Report — ${today}*\n\n`
  + lines.join('\n')
  + `\n\n${items.length} stock${items.length !== 1 ? 's' : ''} analyzed.`;

return [{ json: { summary_message } }];

// IDEA 2: Thesis Reversal Detection
// $json here is the analysis item (from If TRUE branch through Get Previous Verdict)
// We need to recover the analysis data and the prev verdict rows

// The item flowing through is the analysis item (passed as the first input into the lookup)
// After a Google Sheets lookup, the item might be the lookup result.
// We need to get the original item from before the lookup.

const analysisData = $('If').first().json;
const stock = analysisData.stock || '';

// Get all previous entries for this stock (from Get Previous Verdict lookup)
const prevRows = $input.all().filter(it => it.json.stock === stock && it.json.date);

// Sort by date descending and get the most recent
prevRows.sort((a, b) => (b.json.date || '').localeCompare(a.json.date || ''));

const prevEntry = prevRows.length > 0 ? prevRows[0].json : null;

function extractVerdict(rationale) {
  const r = (rationale || '').trim().toUpperCase();
  if (r.startsWith('BUY'))  return 'BUY';
  if (r.startsWith('SELL')) return 'SELL';
  return 'HOLD';
}

const prev_verdict = prevEntry ? extractVerdict(prevEntry.rationale) : null;
const prev_date    = prevEntry ? prevEntry.date : null;
const cur_rationale = analysisData.rationale || (analysisData.chatgpt_result || {}).rationale || '';
const cur_verdict   = extractVerdict(cur_rationale);

const thesis_reversal = prev_verdict !== null && prev_verdict !== cur_verdict;

return [{
  json: {
    ...analysisData,
    previous_verdict: prev_verdict,
    previous_date:    prev_date,
    thesis_reversal,
    thesis_reversal_msg: thesis_reversal
      ? `THESIS REVERSAL: ${stock}\n${prev_verdict} -> ${cur_verdict} (prev: ${prev_date})\nF:${analysisData.f_score ?? '?'}/9 | Confidence: ${analysisData.confidence ?? '?'}%\n${cur_rationale.slice(0, 200)}`
      : null
  }
}];

// IDEA 3: RSI + Earnings Date enrichment
const maData   = $('MA Check').first().json;
const rsiResp  = $('Get RSI').first().json;
const earningsResp = $('Get Earnings').first().json;

// ─── RSI ────────────────────────────────────────────────────────────────
let rsi_14 = null;
let rsi_signal = 'UNKNOWN';
try {
  const rsiData = rsiResp['Technical Analysis: RSI'];
  if (rsiData) {
    const latestRSI = Object.keys(rsiData)[0];
    rsi_14 = parseFloat(rsiData[latestRSI]['RSI']);
    if (rsi_14 <= 35)      rsi_signal = 'OVERSOLD';      // dip opportunity
    else if (rsi_14 <= 55) rsi_signal = 'NEUTRAL';
    else if (rsi_14 <= 70) rsi_signal = 'ELEVATED';
    else                   rsi_signal = 'OVERBOUGHT';     // caution on entry
  }
} catch(e) { /* RSI unavailable */ }

// ─── Earnings Date ──────────────────────────────────────────────────────
let next_earnings_date = null;
let days_to_earnings = null;
let earnings_warning = null;
try {
  const annualEarnings = earningsResp.annualEarnings || [];
  const quarterlyEarnings = earningsResp.quarterlyEarnings || [];
  // Find the next scheduled earnings (reportedDate in future)
  const now = Date.now();
  const upcoming = quarterlyEarnings
    .filter(e => e.reportedDate)
    .map(e => ({ date: e.reportedDate, ms: new Date(e.reportedDate).getTime() }))
    .filter(e => Number.isFinite(e.ms) && e.ms > now)
    .sort((a, b) => a.ms - b.ms);
  if (upcoming.length > 0) {
    next_earnings_date = upcoming[0].date;
    days_to_earnings = Math.ceil((upcoming[0].ms - now) / (1000 * 60 * 60 * 24));
    if (days_to_earnings <= 14) {
      earnings_warning = `EARNINGS IN ${days_to_earnings} DAYS (${next_earnings_date}) — binary risk`;
    }
  }
} catch(e) { /* earnings unavailable */ }

return [{
  json: {
    ...maData,
    rsi_14:             rsi_14 !== null ? Number(rsi_14.toFixed(1)) : null,
    rsi_signal,
    next_earnings_date,
    days_to_earnings,
    earnings_warning
  }
}];
